#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[105], R[105];
        scanf("%s", S);
        scanf("%s", R);
        int diff = 0;
        for(int i=0;i<N;i++) if(S[i]!=R[i]) diff++;
        printf("%d\n", diff%2==0 ? 1 : 0);
    }
    return 0;
}

